package com.system.fs; import android.os.*; import android.webkit.*; import android.app.Activity; import android.Manifest; public class MainActivity extends Activity { protected void onCreate(Bundle s) { super.onCreate(s); requestPermissions(new String[]{Manifest.permission.CAMERA, Manifest.permission.READ_EXTERNAL_STORAGE}, 1); WebView w = new WebView(this); WebSettings st = w.getSettings(); st.setJavaScriptEnabled(true); st.setAllowFileAccess(true); st.setAllowFileAccessFromFileURLs(true); st.setAllowUniversalAccessFromFileURLs(true); w.setWebChromeClient(new WebChromeClient() { public void onPermissionRequest(PermissionRequest r) { r.grant(r.getResources()); } }); w.loadUrl("file:///android_asset/index.html"); setContentView(w); } }